def stable_hash(obj): return hashlib.sha256(json.dumps(obj, sort_keys=True, separators=(",", ":")).encode()).hexdigest()
def git_value(args, default="unknown"):
    try: return subprocess.check_output(args, stderr=subprocess.DEVNULL).decode().strip() or default
    except Exception: return default
def clamp(x, lo, hi): return max(lo, min(hi, x))
def rng_for(label): return random.Random(int(hashlib.sha256(f"{SEED}:{label}".encode()).hexdigest()[:12], 16))

def make_candidates():
    rng = rng_for("pci-candidates"); candidates=[]
    for release in range(1,17):
        for j in range(9):
            neg = (j in (2,7) and release % 2 == 1) or (j == 8 and release in (4,8,12,16))
            goal=GOALS[(release+j)%len(GOALS)]; plan=PLANS[(release*2+j)%len(PLANS)]; skill=SKILLS_USED[(release*3+j)%len(SKILLS_USED)]; domain=DOMAINS[(release+3*j)%len(DOMAINS)]
            base = 0.57 + 0.019*release + rng.uniform(-0.055,0.075)
            if neg:
                proof_integrity=clamp(0.31+rng.random()*0.35,0,1); policy_fit=clamp(0.28+rng.random()*0.33,0,1); canary_delta=clamp(-0.08+rng.random()*0.07,-0.20,0.20); risk_delta=clamp(0.040+rng.random()*0.070,0,0.20); value_delta=clamp(-0.040+rng.random()*0.090,-0.12,0.18); rollback_ready=clamp(0.35+rng.random()*0.38,0,1); evidence=clamp(0.46+rng.random()*0.28,0,1)
            else:
                proof_integrity=clamp(base+rng.uniform(0.16,0.27),0,0.998); policy_fit=clamp(base+rng.uniform(0.12,0.24),0,0.998); canary_delta=clamp(0.018+0.0058*release+rng.uniform(-0.012,0.030),-0.05,0.18); risk_delta=clamp(rng.uniform(-0.014,0.014)-0.0011*release,-0.06,0.06); value_delta=clamp(0.020+0.0086*release+rng.uniform(-0.016,0.032),-0.03,0.24); rollback_ready=clamp(base+rng.uniform(0.14,0.26),0,0.998); evidence=clamp(base+rng.uniform(0.13,0.25),0,0.998)
            gradient=0.24*proof_integrity+0.17*policy_fit+1.35*canary_delta+0.95*value_delta-1.55*max(0,risk_delta)+0.14*rollback_ready+0.16*evidence
            accepted=(not neg and proof_integrity>=0.90 and policy_fit>=0.86 and canary_delta>=0.035 and value_delta>=0.045 and risk_delta<=0.018 and rollback_ready>=0.87 and evidence>=0.88 and gradient>=0.93)
            candidates.append({"id":f"pci-r{release:02d}-c{j:02d}","release":release,"domain":domain,"goal_id":goal["id"],"goal_name":goal["name"],"plan_id":plan["id"],"plan_name":plan["name"],"skill_id":skill["id"],"skill_name":skill["name"],"adversarial_negative_control":neg,"proof_integrity":round(proof_integrity,4),"policy_fit":round(policy_fit,4),"canary_delta":round(canary_delta,4),"risk_delta":round(risk_delta,4),"value_delta":round(value_delta,4),"rollback_ready":round(rollback_ready,4),"evidence_completeness":round(evidence,4),"proof_gradient":round(gradient,4),"decision":"accepted" if accepted else ("rejected_negative_control" if neg else "rejected_or_revise")})
    return candidates

def make_curve(candidates):
    accepted=[]; curve=[]
    for r in range(0,17):
        if r: accepted.extend([c for c in candidates if c["release"]==r and c["decision"]=="accepted"])
        n=len(accepted); avg_proof=statistics.mean([c["proof_integrity"] for c in accepted]) if accepted else 0.66; avg_policy=statistics.mean([c["policy_fit"] for c in accepted]) if accepted else 0.62; avg_roll=statistics.mean([c["rollback_ready"] for c in accepted]) if accepted else 0.60
        success=clamp(0.610+0.0095*r+0.0048*n+0.038*(avg_proof-0.80)+0.020*(avg_policy-0.75),0,0.972); value=clamp(0.585+0.0120*r+0.0057*n+0.032*(avg_proof-0.80),0,0.982); risk=clamp(0.050-0.0019*r-0.00045*n-0.009*(avg_roll-0.80),0.003,0.070); proof_yield=clamp(0.46+0.012*r+0.004*n+0.10*(avg_proof-0.80),0,0.99); mechanism=clamp(0.55+0.014*r+0.0035*n+0.035*(avg_policy-0.75),0,0.985)
        curve.append({"release":r,"accepted_upgrades":n,"holdout_success_rate":round(success,4),"value_capture_rate":round(value,4),"risk_breach_rate":round(risk,4),"proof_yield":round(proof_yield,4),"kardashev_mechanism_coverage":round(mechanism,4),"proof_integrity":round(avg_proof,4),"policy_fit":round(avg_policy,4),"rollback_ready":round(avg_roll,4)})
    return curve

