def write_badge(path, passed, success, value):
    color="#76ffb4" if passed else "#ff6b6b"; label="proof passed" if passed else "proof failed"
    svg=f'''<svg xmlns="http://www.w3.org/2000/svg" width="520" height="46" viewBox="0 0 520 46" role="img" aria-label="Proof-Carrying Intelligence Treasury: {label}"><defs><linearGradient id="g" x1="0" x2="1"><stop offset="0" stop-color="#081525"/><stop offset="0.52" stop-color="#1b2052"/><stop offset="1" stop-color="#39204e"/></linearGradient></defs><rect rx="16" width="520" height="46" fill="url(#g)"/><circle cx="25" cy="23" r="9" fill="{color}"/><text x="44" y="19" fill="#eaf7ff" font-family="Inter,Arial,sans-serif" font-size="12" font-weight="800">PROOF GRADIENT · PROOF-CARRYING INTELLIGENCE TREASURY</text><text x="44" y="35" fill="{color}" font-family="Inter,Arial,sans-serif" font-size="13" font-weight="900">{label.upper()} · {success:.1%} SUCCESS · {value:.1%} VALUE</text></svg>'''
    path.parent.mkdir(parents=True, exist_ok=True); path.write_text(svg, encoding="utf-8")

