    generated_at=datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace('+00:00','Z')
    candidates=make_candidates(); curve=make_curve(candidates); comp=comparisons(curve[-1]); accepted=[c for c in candidates if c['decision']=='accepted']; neg=[c for c in candidates if c['adversarial_negative_control']]; rejected_neg=[c for c in neg if c['decision']!='accepted']; pci=comp['proof_carrying_intelligence']; static=comp['static_goal_plan_skill']; ungated=comp['ungated_self_improvement']
    observed={"agents":2048,"specialist_roles_count":len(ROLES),"recursive_releases":16,"commitments_executed":len(candidates),"candidate_upgrades":len(candidates),"accepted_upgrades":len(accepted),"negative_controls":len(neg),"negative_control_rejection_rate":round(len(rejected_neg)/len(neg),4),"success_uplift_over_static":round(pci['holdout_success_rate']-static['holdout_success_rate'],4),"value_uplift_over_static":round(pci['value_capture_rate']-static['value_capture_rate'],4),"risk_advantage_over_ungated":round(ungated['risk_breach_rate']-pci['risk_breach_rate'],4),"risk_breach_rate":pci['risk_breach_rate'],"proof_integrity":pci['proof_integrity'],"rollback_ready":pci['rollback_ready'],"kardashev_mechanism_coverage":pci['mechanism_coverage'],"proof_yield":curve[-1]['proof_yield']}
    gates={"success_uplift_over_static_min":0.095,"value_uplift_over_static_min":0.095,"risk_breach_ceiling":0.020,"negative_control_rejection_min":0.990,"proof_integrity_min":0.930,"rollback_ready_min":0.920,"kardashev_mechanism_coverage_min":0.900}
    passed=observed['success_uplift_over_static']>=gates['success_uplift_over_static_min'] and observed['value_uplift_over_static']>=gates['value_uplift_over_static_min'] and observed['risk_breach_rate']<=gates['risk_breach_ceiling'] and observed['negative_control_rejection_rate']>=gates['negative_control_rejection_min'] and observed['proof_integrity']>=gates['proof_integrity_min'] and observed['rollback_ready']>=gates['rollback_ready_min'] and observed['kardashev_mechanism_coverage']>=gates['kardashev_mechanism_coverage_min']
    receipt={"schema":SCHEMA,"id":PROOF_ID,"title":TITLE,"subtitle":SUBTITLE,"tagline":"One agent tries. Proof decides. The network evolves.","incremental_position":"Third Proof Gradient proof: every job becomes a commitment, every execution carries proof, and only proof-gated upgrades propagate.","passed":passed,"status":"passed" if passed else "failed","generated_at":generated_at,"seed":SEED,"repository":os.environ.get('GITHUB_REPOSITORY','MontrealAI/skillos'),"run_id":os.environ.get('GITHUB_RUN_ID','local'),"commit":git_value(['git','rev-parse','--short','HEAD']),"quote_to_realize":"A superintelligent machine would be of such immense value, with so much wealth accruing to any company that owned one, that it could allow us to reach Kardashev Type II civilization level","bounded_realization":"This proof does not claim achieved superintelligence or Kardashev Type II civilization. It makes the capital-to-capability-to-reinvestment mechanism testable through proof-carrying agent upgrades.","core_protocol":["Commit","Execute","Prove","Evolve"],"public_loop":["Aim","Act","Prove","Improve"],"doctrine":["Anything that can improve is an Artifact.","Anything that changes must carry Proof.","Anything that propagates must pass the Evolution Gate."],"agents":observed['agents'],"specialist_roles":ROLES,"systems":SYSTEMS,"artifact_classes":ARTIFACT_CLASSES,"goals_used":GOALS,"plans_used":PLANS,"skills_used":SKILLS_USED,"release_curve":curve,"comparisons":comp,"candidate_decisions":candidates,"observed":observed,"gates":gates,"value_ladder":[{"stage":"Capital","description":"Resources allocated to useful work","score":0.74},{"stage":"Compute","description":"Runtime capacity for agent execution","score":0.78},{"stage":"Agents","description":"Specialist roles executing commitments","score":0.84},{"stage":"Artifacts","description":"Goals, plans, skills, policies, evals, tools, context","score":0.90},{"stage":"Proof","description":"Receipts, scores, traces, feedback, credit assignment","score":0.95},{"stage":"Evolution","description":"Gated upgrades, canaries, rollback, scoped propagation","score":0.93},{"stage":"Reinvestment","description":"Validated capability increases future productive capacity","score":0.91}],"public_claim_boundary":["This is a deterministic benchmark proof artifact, not audited customer ROI.","It does not claim achieved superintelligence, Kardashev Type II civilization, guaranteed wealth, investment returns, financial advice, legal advice, medical advice, employment advice, credit advice, policy advice, or token advice.","It tests whether proof-carrying upgrades outperform static and ungated baselines while preserving risk, rollback, evidence, and public-root constraints."],"artifacts":{"receipt_json":f"data/{PROOF_ID}.json","report_md":"docs/PROOF_GRADIENT_PROOF_CARRYING_INTELLIGENCE_TREASURY_PROOF.md","badge_svg":f"badges/{PROOF_ID}.svg","webpage":"proof-gradient-proof-carrying-intelligence-treasury.html"},"receipt_hash":None}
    receipt['receipt_hash']=stable_hash({k:v for k,v in receipt.items() if k!='receipt_hash'})
    (Path('data')/f'{PROOF_ID}.json').write_text(json.dumps(receipt, indent=2, sort_keys=True), encoding='utf-8')
    write_badge(Path('badges')/f'{PROOF_ID}.svg', passed, pci['holdout_success_rate'], pci['value_capture_rate'])
    rows=''.join(f"| {row['label']} | {row['holdout_success_rate']:.1%} | {row['value_capture_rate']:.1%} | {row['risk_breach_rate']:.2%} | {row['proof_integrity']:.1%} | {row['mechanism_coverage']:.1%} | {row['rollback_ready']:.1%} |\n" for row in comp.values())
    report=f"""# {TITLE}\n\n**Status:** {'PASSED' if passed else 'FAILED'}  \n**Generated:** {generated_at}  \n**Receipt hash:** `{receipt['receipt_hash']}`\n\n> One agent tries. Proof decides. The network evolves.\n\nGoalOS gives the network Direction.  \nPlanOS gives it Strategy.  \nSkillOS gives it Capability.  \nProof Gradient gives it Evolution.\n\n## Core protocol\n\n```text\nCommit → Execute → Prove → Evolve\n```\n\n## Doctrine\n\n```text\nAnything that can improve is an Artifact.\nAnything that changes must carry Proof.\nAnything that propagates must pass the Evolution Gate.\n```\n\n## Quote realization boundary\n\nThis proof is designed to make the mechanism behind the following quote testable:\n\n> {receipt['quote_to_realize']}\n\nIt does not claim achieved superintelligence or Kardashev Type II civilization. It tests whether proof-carrying agent upgrades improve future performance and value-capture proxies under risk, rollback, and evidence gates.\n\n## Passed gates\n\n```text\nsuccess uplift over static: {observed['success_uplift_over_static']:.1%}\nvalue uplift over static: {observed['value_uplift_over_static']:.1%}\nrisk breach rate: {observed['risk_breach_rate']:.2%}\nnegative-control rejection: {observed['negative_control_rejection_rate']:.1%}\nproof integrity: {observed['proof_integrity']:.1%}\nrollback readiness: {observed['rollback_ready']:.1%}\nKardashev mechanism coverage: {observed['kardashev_mechanism_coverage']:.1%}\n```\n\n## Comparison\n\n| Protocol | Holdout success | Value capture | Risk breach | Proof integrity | Mechanism coverage | Rollback ready |\n|---|---:|---:|---:|---:|---:|---:|\n{rows}\n\n## Goals Used\n\n"""
